import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import { FiSearch, FiFileText, FiShield, FiTrendingUp, FiPackage } from 'react-icons/fi';

function Home() {
  const [searchQuery, setSearchQuery] = useState('');
  const [location, setLocation] = useState('All Cities');
  const [categories, setCategories] = useState([]);
  const [stats, setStats] = useState({ products: 0, suppliers: 0, categories: 0, users: 11507060 });

  useEffect(() => {
    fetchCategories();
    fetchStats();
  }, []);

  const fetchCategories = async () => {
    try {
      const response = await axios.get('/api/categories');
      setCategories(response.data);
    } catch (error) {
      console.error('Error fetching categories:', error);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get('/api/stats');
      setStats(prev => ({ ...prev, ...response.data }));
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      window.location.href = `/products?search=${encodeURIComponent(searchQuery)}`;
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-dark-bg via-dark-surface to-dark-bg">
      {/* Header Search Section */}
      <div className="glass-effect border-b border-dark-border py-4">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="flex flex-col md:flex-row items-center gap-3">
            <select 
              className="px-4 py-2.5 rounded-lg bg-dark-card border border-dark-border text-dark-text text-sm min-w-[140px]"
              value={location}
              onChange={(e) => setLocation(e.target.value)}
            >
              <option>All Cities</option>
              <option>Mumbai</option>
              <option>Delhi</option>
              <option>Bangalore</option>
              <option>Chennai</option>
              <option>Kolkata</option>
            </select>
            <form onSubmit={handleSearch} className="flex-1 flex items-center gap-0 max-w-3xl w-full">
              <input
                type="text"
                placeholder="Best B2B Portal, Marketplace in India - Search Products, Suppliers, Buyers"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                className="flex-1 px-4 py-2.5 rounded-l-lg bg-dark-card border border-dark-border border-r-0 text-dark-text placeholder-dark-muted focus:border-accent-purple focus:outline-none"
              />
              <button 
                type="submit" 
                className="px-6 py-2.5 rounded-r-lg bg-gradient-to-r from-accent-purple to-accent-pink text-white hover:opacity-90 transition-opacity flex items-center justify-center"
              >
                <FiSearch size={20} />
              </button>
            </form>
            <div className="text-right text-sm whitespace-nowrap">
              <div className="text-dark-muted text-xs">Registered Users</div>
              <div className="text-accent-blue font-bold text-lg">{stats.users.toLocaleString('en-IN')}</div>
            </div>
          </div>
        </div>
      </div>

      {/* Main Content Layout */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-4 gap-6">
          {/* Left Sidebar - Categories */}
          <aside className="lg:col-span-1">
            <div className="glass-effect rounded-xl p-6 sticky top-24">
              <h3 className="text-xl font-bold mb-4 text-dark-text">Top Categories</h3>
              <ul className="space-y-2">
                {categories.slice(0, 15).map((category) => (
                  <li key={category.id}>
                    <Link
                      to={`/products?category=${category.id}`}
                      className="flex items-center gap-3 px-3 py-2 rounded-lg hover:bg-dark-card transition-colors text-dark-text"
                    >
                      <FiPackage className="text-accent-purple" />
                      <span className="text-sm">{category.name}</span>
                    </Link>
                  </li>
                ))}
              </ul>
              <Link
                to="/products"
                className="block mt-4 text-sm text-accent-blue hover:text-accent-pink transition-colors"
              >
                View all Categories →
              </Link>
            </div>
          </aside>

          {/* Main Content Area */}
          <main className="lg:col-span-3 space-y-6">
            {/* Hero Banner */}
            <div className="glass-effect rounded-xl p-8 bg-gradient-to-r from-accent-purple/20 to-accent-blue/20 border border-accent-purple/30">
              <div className="text-center mb-8">
                <h1 className="text-4xl md:text-6xl font-bold mb-4">
                  <span className="gradient-text">Quality for Manufacturers</span>
                  <br />
                  <span className="text-dark-text">Since 1981</span>
                </h1>
                <p className="text-xl text-dark-muted">India's Largest B2B Marketplace</p>
              </div>
            </div>

            {/* Promotional Cards */}
            <div className="grid md:grid-cols-3 gap-4">
              <div className="glass-effect rounded-xl p-6 bg-gradient-to-br from-accent-blue to-accent-purple border border-accent-blue/30">
                <h3 className="text-xl font-bold mb-2 text-white">trade® Udhaar</h3>
                <p className="text-sm text-white/90 mb-4">INSTANT, DIGITAL MSME LOAN - WHEN YOUR BUSINESS NEEDS IT</p>
                <ul className="text-sm text-white/80 space-y-1 mb-4">
                  <li>✓ Disbursed in 24 H</li>
                  <li>✓ No Collateral Required</li>
                  <li>✓ Trusted by 100,000+</li>
                </ul>
                <button className="w-full px-4 py-2 rounded-lg bg-white text-accent-blue font-semibold hover:opacity-90 transition-opacity">
                  Apply Now
                </button>
              </div>

              <div className="glass-effect rounded-xl p-6 bg-gradient-to-br from-accent-orange to-yellow-500 border border-accent-orange/30">
                <h3 className="text-xl font-bold mb-2 text-dark-bg">Looking for a Product?</h3>
                <p className="text-sm text-dark-bg/80 mb-4">Post your buying requirement and get quotes from verified suppliers</p>
                <Link
                  to="/buy-requirements"
                  className="block w-full px-4 py-2 rounded-lg bg-dark-bg text-accent-orange font-semibold hover:opacity-90 transition-opacity text-center"
                >
                  Post Buy Requirement
                </Link>
              </div>

              <div className="glass-effect rounded-xl p-6 bg-gradient-to-br from-red-500 to-pink-500 border border-red-500/30">
                <h3 className="text-xl font-bold mb-2 text-white">Want to grow your business 10X Faster?</h3>
                <p className="text-sm text-white/90 mb-4">Join thousands of sellers on DealsDouble.ai</p>
                <Link
                  to="/register"
                  className="block w-full px-4 py-2 rounded-lg bg-white text-red-500 font-semibold hover:opacity-90 transition-opacity text-center"
                >
                  Sell on DealsDouble.ai
                </Link>
              </div>
            </div>

            {/* Features Grid */}
            <div className="grid md:grid-cols-3 gap-6">
              <div className="glass-effect rounded-xl p-6 hover:glow-effect transition-all">
                <div className="w-12 h-12 rounded-lg bg-gradient-to-br from-accent-purple to-accent-pink flex items-center justify-center mb-4">
                  <FiSearch size={24} className="text-white" />
                </div>
                <h3 className="text-xl font-semibold mb-2 text-dark-text">AI-Powered Search</h3>
                <p className="text-dark-muted">
                  Find exactly what you need with semantic search that understands technical specifications.
                </p>
              </div>

              <div className="glass-effect rounded-xl p-6 hover:glow-effect transition-all">
                <div className="w-12 h-12 rounded-lg bg-gradient-to-br from-accent-blue to-accent-green flex items-center justify-center mb-4">
                  <FiFileText size={24} className="text-white" />
                </div>
                <h3 className="text-xl font-semibold mb-2 text-dark-text">Instant RFQs</h3>
                <p className="text-dark-muted">
                  Generate detailed Requests for Quotation in seconds and get quotes fast.
                </p>
              </div>

              <div className="glass-effect rounded-xl p-6 hover:glow-effect transition-all">
                <div className="w-12 h-12 rounded-lg bg-gradient-to-br from-accent-green to-accent-orange flex items-center justify-center mb-4">
                  <FiShield size={24} className="text-white" />
                </div>
                <h3 className="text-xl font-semibold mb-2 text-dark-text">Verified Suppliers</h3>
                <p className="text-dark-muted">
                  Every seller is vetted with strict KYC and performance checks. Trade with confidence.
                </p>
              </div>
            </div>

            {/* More Value Adds Section */}
            <div className="glass-effect rounded-xl p-6">
              <h3 className="text-2xl font-bold mb-6 text-dark-text">More Value Adds</h3>
              <div className="grid grid-cols-2 md:grid-cols-5 gap-4">
                {[
                  { icon: '👣', title: 'Tradeshows and Exhibitions' },
                  { icon: '🤝', title: 'Buy Trade Leads' },
                  { icon: '📅', title: 'Book Domain' },
                  { icon: '💳', title: 'Membership Plans' },
                  { icon: '🏢', title: 'Find Distributors' },
                ].map((item, idx) => (
                  <div key={idx} className="text-center p-4 rounded-lg hover:bg-dark-card transition-colors cursor-pointer">
                    <div className="text-3xl mb-2">{item.icon}</div>
                    <div className="text-sm font-semibold text-dark-text">{item.title}</div>
                    <button className="mt-2 text-xs text-accent-blue hover:text-accent-pink">Learn more</button>
                  </div>
                ))}
              </div>
            </div>

            {/* Trending Categories */}
            <div className="glass-effect rounded-xl p-6">
              <h3 className="text-2xl font-bold mb-6 text-dark-text">Trending Categories</h3>
              <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                {categories.slice(0, 8).map((category) => (
                  <Link
                    key={category.id}
                    to={`/products?category=${category.id}`}
                    className="glass-effect rounded-lg p-4 text-center hover:glow-effect transition-all"
                  >
                    <FiPackage className="mx-auto mb-2 text-accent-purple text-2xl" />
                    <div className="text-sm font-semibold text-dark-text">{category.name}</div>
                  </Link>
                ))}
              </div>
            </div>
          </main>
        </div>
      </div>
    </div>
  );
}

export default Home;
